import{bQ as a,aL as i,u as t,G as n}from"./chunks/framework.D06dwy5q.js";const y=JSON.parse('{"title":"01｜Python 是什么与安装","description":"","frontmatter":{},"headers":[],"relativePath":"18.Python脚本/01-Python是什么与安装.md","filePath":"18.Python脚本/01-Python是什么与安装.md","lastUpdated":null}'),h={name:"18.Python脚本/01-Python是什么与安装.md"};function e(p,s,l,o,d,r){return i(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="_01-python-是什么与安装" tabindex="-1">01｜Python 是什么与安装 <a class="header-anchor" href="#_01-python-是什么与安装" aria-label="Permalink to &quot;01｜Python 是什么与安装&quot;">​</a></h1><p>Python 是一门解释型、动态类型、通用编程语言。它的语法接近自然语言，代码可读性高，标准库覆盖了文件处理、网络通信、文本解析、数据序列化等常见任务。</p><p>在自动化运维、数据分析、Web 开发、人工智能等领域，Python 都是主流选择之一。它的核心优势不是执行速度，而是开发效率和生态丰富度——同样的功能，用 Python 实现通常代码量更少，第三方库也更容易找到。</p><h2 id="一、解释型语言" tabindex="-1">一、解释型语言 <a class="header-anchor" href="#一、解释型语言" aria-label="Permalink to &quot;一、解释型语言&quot;">​</a></h2><p>Python 代码不是直接交给操作系统执行的。它需要先经过解释器（interpreter），把 <code>.py</code> 文件逐行翻译成机器能理解的指令。</p><div class="mermaid-diagram" data-mermaid-code="flowchart%20LR%0A%20%20%20%20source%5B%22.py%20%E6%BA%90%E7%A0%81%22%5D%20--%3E%20interpreter%5B%22Python%20%E8%A7%A3%E9%87%8A%E5%99%A8%22%5D%0A%20%20%20%20interpreter%20--%3E%20bytecode%5B%22%E5%AD%97%E8%8A%82%E7%A0%81%22%5D%0A%20%20%20%20bytecode%20--%3E%20vm%5B%22Python%20%E8%99%9A%E6%8B%9F%E6%9C%BA%22%5D%0A%20%20%20%20vm%20--%3E%20os%5B%22%E6%93%8D%E4%BD%9C%E7%B3%BB%E7%BB%9F%22%5D%0A"></div><p>这个流程意味着：</p><ul><li>运行 Python 程序前，目标机器上必须有对应版本的解释器</li><li>同一段代码在不同操作系统上都能运行（跨平台）</li><li>解释器版本很重要——Python 3.6 能跑的 f-string，Python 3.5 会直接报语法错误</li></ul><h2 id="二、安装-python" tabindex="-1">二、安装 Python <a class="header-anchor" href="#二、安装-python" aria-label="Permalink to &quot;二、安装 Python&quot;">​</a></h2><h3 id="linux" tabindex="-1">Linux <a class="header-anchor" href="#linux" aria-label="Permalink to &quot;Linux&quot;">​</a></h3><p>RHEL / Rocky / CentOS：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-pip</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>Ubuntu / Debian：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt-get</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-venv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3-pip</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>系统仓库的 Python 版本可能偏旧。需要新版本时，从 python.org 下载源码或二进制包自行安装。</p><h3 id="windows" tabindex="-1">Windows <a class="header-anchor" href="#windows" aria-label="Permalink to &quot;Windows&quot;">​</a></h3><p>从 python.org 下载安装包，安装时勾选 &quot;Add Python to PATH&quot;。安装完成后：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">0p</span></span></code></pre></div><p><code>py</code> 是 Windows 上的 Python 启动器，可以管理多个 Python 版本。<code>py -0p</code> 列出所有已安装的版本和路径。</p><h3 id="macos" tabindex="-1">macOS <a class="header-anchor" href="#macos" aria-label="Permalink to &quot;macOS&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><h2 id="三、版本选择" tabindex="-1">三、版本选择 <a class="header-anchor" href="#三、版本选择" aria-label="Permalink to &quot;三、版本选择&quot;">​</a></h2><p>当前 Python 有两个大版本：</p><table tabindex="0"><thead><tr><th>版本</th><th>状态</th></tr></thead><tbody><tr><td>Python 2</td><td>已于 2020 年停止维护，不应在新项目中使用</td></tr><tr><td>Python 3</td><td>当前主流，Python 3.9 及以上版本推荐</td></tr></tbody></table><p>新学习的项目直接选 Python 3。Python 3.8 之后的版本引入了 <code>:=</code> 海象运算符、更精确的类型注解、<code>match-case</code> 语法等特性。如果教程里用到这些语法，需要确认解释器版本是否支持。</p><h2 id="四、验证安装" tabindex="-1">四、验证安装 <a class="header-anchor" href="#四、验证安装" aria-label="Permalink to &quot;四、验证安装&quot;">​</a></h2><p>安装完成后，确认三个基本要素：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 解释器版本</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> python3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 解释器路径</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pip</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # pip 版本</span></span></code></pre></div><p><code>python3 -m pip</code> 是用当前解释器运行 pip 模块。当系统上同时存在 <code>python</code>、<code>python3</code>、<code>py</code> 多个命令时，这个写法能确保用的是同一个解释器对应的包管理器，避免装错环境。</p><p><strong>记忆锚点</strong>：Python 是解释型语言，需要解释器才能运行；Python 2 已停止维护，新项目用 Python 3；<code>python3 -m pip</code> 确保包装到正确的环境里。</p>`,30)])])}const c=a(h,[["render",e]]);export{y as __pageData,c as default};
